WITH
    arrayMap(i -> toFloat32((cityHash64(toUInt64(1001), i) % 1000000) / 1000000.), range(toUInt64({dims}))) AS ref1,
    arrayMap(i -> toFloat32((cityHash64(toUInt64(1002), i) % 1000000) / 1000000.), range(toUInt64({dims}))) AS ref2,
    arrayMap(i -> toFloat32((cityHash64(toUInt64(1003), i) % 1000000) / 1000000.), range(toUInt64({dims}))) AS ref3,
    arrayMap(i -> toFloat32((cityHash64(toUInt64(1004), i) % 1000000) / 1000000.), range(toUInt64({dims}))) AS ref4
SELECT sum(id)
FROM
(
    SELECT id FROM vector_search_pdx_hnsw ORDER BY cosineDistance(vec, ref1) ASC LIMIT {k}
    UNION ALL
    SELECT id FROM vector_search_pdx_hnsw ORDER BY cosineDistance(vec, ref2) ASC LIMIT {k}
    UNION ALL
    SELECT id FROM vector_search_pdx_hnsw ORDER BY cosineDistance(vec, ref3) ASC LIMIT {k}
    UNION ALL
    SELECT id FROM vector_search_pdx_hnsw ORDER BY cosineDistance(vec, ref4) ASC LIMIT {k}
)
SETTINGS hnsw_candidate_list_size_for_search = {ef}
FORMAT Null

